public static String trimControl(final String str) {
        if (str == null) {
            return null;
        }
        int len = str.length();
        int st = 0;

        while (st < len && str.charAt(st) < ' ') {
            st++;
        }
        while (st < len && str.charAt(len - 1) < ' ') {
            len--;
        }
        return st > 0 || len < str.length() ? str.substring(st, len) : str;
    }
